(86, 'Lightyear', 'Animáció', 100, 'PG', 'Buzz Lightyear eredettörténete a sci-fi film formájában.', 'movies/lightyear_86.jpg', '2022-06-17', '2026-03-16 10:04:41'),
(87, 'Transformers One', 'Animáció', 104, 'PG', 'Optimus Prime és Megatron eredettörténete Cybertronon.', 'movies/transformers_one_87.webp', '2024-09-20', '2026-03-16 10:04:41'),
(88, 'Sonic 2. – A film', 'Kaland', 122, 'PG', 'Sonic szembeszáll a visszatérő Dr. Robotnikkal.', 'movies/sonic_2____a_film_88.jpg', '2022-04-08', '2026-03-16 10:04:41'),
(89, 'Minions: Gru születése', 'Animáció', 87, 'PG', 'A fiatal Gru próbál a világ leghírhedtebb szupergonoszaival dolgozni.', 'movies/minions__gru_sz_let_se_89.jpg', '2022-07-01', '2026-03-16 10:04:41'),
(90, 'Thor: Szerelem és mennydörgés', 'Akció', 119, 'PG-13', 'Thor nyugalomra vágyó útját megszakítja egy galaktikus gyilkos küldetése.', 'movies/thor__szerelem__s_mennyd_rg_s_90.jpg', '2022-07-08', '2026-03-16 10:04:41'),
(91, 'Jurassic World: Uralom', 'Kaland', 147, 'PG-13', 'Az emberek és a dinoszauruszok együtt élnek — de ez az egyensúly törékeny.', 'movies/jurassic_world__uralom_91.png', '2022-06-10', '2026-03-16 10:04:41'),
(92, 'Sonic 1. – A film', 'Kaland', 99, 'PG', 'Sonic és Tom rendőr barátja megpróbálják megállítani Dr. Robotnikot.', 'movies/sonic_1____a_film_92.jpg', '2020-02-14', '2026-03-16 10:04:41'),
(93, 'Hang nélkül 2 ', 'Horror', 97, 'PG-13', 'Az Abbott család tovább küzd a hangra vadászó lényekkel.', 'movies/hang_n_lk_l_2__93.jpg', '2021-05-28', '2026-03-16 10:04:41'),
(94, 'Open Water 2: Adrift', 'Thriller', 118, 'PG-13', 'Egy hajó legénysége harcol a természet erői ellen.', 'movies/open_water_2__adrift_94.jpg', '2024-03-15', '2026-03-16 10:04:41'),
(95, 'Pearl', 'Horror', 102, 'R', 'Egy farmon élő fiatal lány csillaggá akar válni.', 'movies/pearl_95.jpg', '2022-09-16', '2026-03-16 10:04:41'),
