(97, 'Insidious: A vörös ajtó', 'Horror', 107, 'PG-13', 'A Lambert család újból szembekerül a szellemekkel.', 'movies/insidious__a_v_r_s_ajt__97.webp', '2023-07-07', '2026-03-16 10:04:41'),
(98, 'The Popes Exorcist', 'Horror', 103, 'R', 'I. János Pál pápa exorcistájának igaz kalandjain alapuló film.', 'movies/the_popes_exorcist_98.webp', '2023-04-14', '2026-03-16 10:04:41'),
(99, 'Babylon', 'Dráma', 189, 'R', 'Hollywood aranykorában játszódó mámoros és kaotikus történet.', 'movies/babylon_99.webp', '2022-12-23', '2026-03-16 10:04:41'),
